
import * as THREE from 'three';
import { OrbitControls } from 'three/examples/jsm/controls/OrbitControls.js';
import { Pane } from 'tweakpane';
import Stats from 'three/examples/jsm/libs/stats.module.js';

import { getAssetURL, getRenderLoopController } from '/extend/tools/Tool.js';
import { HEIGHT_WARP_VERTEX, HEIGHT_WARP_FRAGMENT } from '/extend/effect/legacy/Effect.js';

const assetUrl = getAssetURL();
const renderLoop = getRenderLoopController();

let options = {
    radius: 100,
    segments: 640,
    factor: 5,
    map: assetUrl + 'textures/8081_earthmap4k.jpg',
    bump: assetUrl + 'textures/8081_earthbump4k.jpg'
};

const BG_COLOR = 0x111111;
const FRAME_RATE = 30;

let renderer;
let camera, controller;
let scene;
let loader;
let geometry, material, mesh;
let stats, pane;

init();

function initThree() {
    let width = window.innerWidth;
    let height = window.innerHeight;
    renderer = new THREE.WebGLRenderer({
        antialias: true
    });
    renderer.setSize(width, height);
    renderer.setClearColor(BG_COLOR, 1);
    document.body.appendChild(renderer.domElement);

    let near = 0.1;
    let far = 10000;
    camera = new THREE.PerspectiveCamera(80, width / height, near, far);
    camera.position.set(0, 200, 0);
    camera.up.set(0, 1, 0);
    controller = new OrbitControls(camera, renderer.domElement);
    controller.target = new THREE.Vector3(0, 0, 0);
    controller.update();
    controller.addEventListener('change', () => {
        renderLoop.requestRender();
    });

    loader = new THREE.TextureLoader();

    pane = new Pane({ title: 'HeightWarp' });
    pane.addBinding(options, 'factor', { min: 0, max: 50, step: 0.1 }).on('change', (ev) => {
        material.uniforms.u_factor.value = ev.value;
        renderLoop.requestRender();
    });

    stats = new Stats();
    document.body.appendChild(stats.dom);

    renderLoop.configure({
        fps: FRAME_RATE,
        render: renderFrame
    });
    renderLoop.setRenderOnIdle(false);

    window.addEventListener('resize', e => {

        let windwoWidth = window.innerWidth;
        let windowHeight = window.innerHeight;
        camera.aspect = windwoWidth / windowHeight;
        camera.updateProjectionMatrix();

        renderer.setSize(windwoWidth, windowHeight);
        renderLoop.requestRender();
    });
}

function initScene() {
    scene = new THREE.Scene();

    let ambientLight = new THREE.AmbientLight(0xfefefe);
    let directionLight = new THREE.DirectionalLight(0xffffff);
    directionLight.position.set(0, 5, 0);
    directionLight.intensity = 2;
    scene.add(ambientLight);
    scene.add(directionLight);

    geometry = new THREE.SphereGeometry(options.radius, options.segments, options.segments);
    material = new THREE.ShaderMaterial({
        uniforms: {
            u_radius: {
                value: options.radius
            },
            u_factor: {
                type: 'f',
                value: options.factor
            },
            u_map: {
                value: loader.load(options.map)
            },
            u_bump: {
                value: loader.load(options.bump)
            },
            u_color: {
                value: new THREE.Color('rgb(255, 255, 255)')
            },
        },
        transparent: true,
        vertexShader: HEIGHT_WARP_VERTEX,
        fragmentShader: HEIGHT_WARP_FRAGMENT,
    });
    mesh = new THREE.Mesh(geometry, material);
    scene.add(mesh);
}

function renderFrame() {
    stats.update();
    renderer.render(scene, camera);
}

function init() {
    initThree();
    initScene();
    renderLoop.requestRender();
}
